<template><view class="page"><view class="filters"><input v-model="keyword" placeholder="搜索商品" confirm-type="search" @confirm="reload"/><picker :range="sortLabels" @change="changeSort"><view>{{sortLabels[sortIndex]}}</view></picker></view><view class="tabs"><view v-for="z in zones" :key="z.value" :class="{on:zoneType===z.value}" @click="setZone(z.value)">{{z.label}}</view></view><PageState :loading="loading" :empty="products.length===0" empty-text="暂无商品"><view class="grid list"><view v-for="p in products" :key="p.id" class="item" @click="goDetail(p)"><image v-if="p.mainImage" :src="p.mainImage" mode="aspectFill"/><view v-else class="ph"></view><text class="name">{{p.name}}</text><text class="price">¥{{p.discountPrice || p.price}}</text><text class="muted">等级价/赠送积分以详情为准</text></view></view></PageState></view></template>
<script setup lang="ts">import { ref } from 'vue';import { onLoad,onPullDownRefresh,onShow } from '@dcloudio/uni-app';import PageState from '@/components/PageState/PageState.vue';import { productApi } from '@/services/product';import { listOf } from '@/utils/format';const products=ref<any[]>([]),loading=ref(false),keyword=ref(''),zoneType=ref(''),sortIndex=ref(0);const sortLabels=['综合','价格升序','销量优先'];const zones=[{label:'全部',value:''},{label:'主产品',value:'main'},{label:'招商',value:'investment'},{label:'零售',value:'retail'},{label:'礼包',value:'gift'}];async function load(){loading.value=true;try{const res=await productApi.list({keyword:keyword.value,zoneType:zoneType.value,sort:sortIndex.value});products.value=listOf(res.data)}finally{loading.value=false}}function reload(){load()}function changeSort(e:any){sortIndex.value=Number(e.detail.value);load()}function setZone(v:string){zoneType.value=v;load()}function goDetail(p:any){uni.navigateTo({url:'/pages/product/detail/index?id='+p.id})}onLoad((o:any)=>{zoneType.value=o.zoneType||''});onShow(load);onPullDownRefresh(async()=>{await load();uni.stopPullDownRefresh()})</script>
<style scoped lang="scss">.page{min-height:100vh;background:#f6f1e8;color:#24170c}.filters{display:grid;grid-template-columns:1fr 180rpx;gap:16rpx;padding:20rpx;background:#fff}.filters input,.filters picker{height:76rpx;line-height:76rpx;background:#f8f4ed;border-radius:12rpx;padding:0 20rpx}.tabs{display:flex;gap:16rpx;overflow:auto;padding:20rpx}.tabs view{white-space:nowrap;background:#fff;padding:16rpx 22rpx;border-radius:999rpx}.tabs .on{background:#2b1207;color:#f0bf55}.grid{display:grid;grid-template-columns:repeat(2,1fr);gap:18rpx}.list{padding:0 20rpx}.item{background:#fff;border-radius:16rpx;padding:18rpx}.item image,.ph{width:100%;height:230rpx;border-radius:12rpx;background:#ead7b8}.name{display:block;margin:14rpx 0;font-weight:800;font-size:27rpx}.price{color:#b97700;font-weight:900}.muted{color:#8d8175;font-size:22rpx}</style>
